+                            child.node_value = merged;
+                        }
+                    }
+                    _ = self.child_nodes.orderedRemove(i + 1);
+                    next.deinit();
+                    self.allocator.destroy(next);
+                    continue;
+                }
+            }
+            child.normalize();
+            i += 1;
+        }
+    }
