+    /// Get next sibling
+    pub fn nextSibling(self: *const Self) ?*Node {
+        if (self.parent_node) |parent| {
+            for (parent.child_nodes.items, 0..) |child, i| {
+                if (child == self and i + 1 < parent.child_nodes.items.len) {
+                    return parent.child_nodes.items[i + 1];
+                }
+            }
+        }
+        return null;
+    }
